  1→import { useEffect, useId, useRef, useState, type ReactNode } from 'react';
  2→import './alert.scss';
  3→
  4→export type AlertActionStyle = 'default' | 'destructive' | 'cancel';
  5→
  6→export interface AlertAction {
  7→  label: string;
  8→  style?: AlertActionStyle;
  9→  onAction: () => void;
 10→}
 11→
 12→export interface AlertOptions {
 13→  title: string;
 14→  message?: string;
 15→  icon?: ReactNode;
 16→  primaryAction: AlertAction;
 17→  dismissAction?: AlertAction;
 18→}
 19→
 20→interface AlertProps extends AlertOptions {
 21→  onDismiss: (confirmed: boolean) => void;
 22→}
 23→
 24→const EXIT_ANIMATION_MS = 150;
 25→
 26→export function Alert({
 27→  title,
 28→  message,
 29→  icon,
 30→  primaryAction,
 31→  dismissAction,
 32→  onDismiss,
 33→}: AlertProps) {
 34→  const dialogRef = useRef<HTMLDivElement>(null);
 35→  const primaryRef = useRef<HTMLButtonElement>(null);
 36→  const onDismissRef = useRef(onDismiss);
 37→  const dismissActionRef = useRef(dismissAction);
 38→  const [exiting, setExiting] = useState(false);
 39→  const titleId = useId();
 40→  const messageId = useId();
 41→
 42→  onDismissRef.current = onDismiss;
 43→  dismissActionRef.current = dismissAction;
 44→
 45→  useEffect(() => {
 46→    primaryRef.current?.focus();
 47→  }, []);
 48→
 49→  function animateOut(confirmed: boolean) {
 50→    if (exiting) return;
 51→    setExiting(true);
 52→    setTimeout(() => {
 53→      onDismissRef.current(confirmed);
 54→    }, EXIT_ANIMATION_MS);
 55→  }
 56→
 57→  useEffect(() => {
 58→    function handleKeyDown(e: KeyboardEvent) {
 59→      if (e.key === 'Escape') {
 60→        e.preventDefault();
 61→        e.stopPropagation();
 62→        dismissActionRef.current?.onAction();
 63→        onDismissRef.current(false);
 64→        return;
 65→      }
 66→      if (e.key === 'Tab') {
 67→        const focusable = dialogRef.current?.querySelectorAll<HTMLElement>(
 68→          'button:not([disabled])',
 69→        );
 70→        if (!focusable || focusable.length === 0) return;
 71→
 72→        const first = focusable.item(0);
 73→        const last = focusable.item(focusable.length - 1);
 74→        if (!first || !last) return;
 75→
 76→        if (e.shiftKey) {
 77→          if (document.activeElement === first) {
 78→            e.preventDefault();
 79→            last.focus();
 80→          }
 81→        } else {
 82→          if (document.activeElement === last) {
 83→            e.preventDefault();
 84→            first.focus();
 85→          }
 86→        }
 87→      }
 88→    }
 89→
 90→    window.addEventListener('keydown', handleKeyDown, true);
 91→    return () => window.removeEventListener('keydown', handleKeyDown, true);
 92→  }, []);
 93→
 94→  function handleBackdropClick(e: React.MouseEvent) {
 95→    if (e.target === e.currentTarget) {
 96→      dismissAction?.onAction();
 97→      animateOut(false);
 98→    }
 99→  }
100→
101→  function handlePrimaryClick() {
102→    primaryAction.onAction();
103→    animateOut(true);
104→  }
105→
106→  function handleDismissClick() {
107→    dismissAction?.onAction();
108→    animateOut(false);
109→  }
110→
111→  const primaryClassName = `alert__button alert__button--${primaryAction.style ?? 'default'}`;
112→
113→  return (
114→    <div
115→      className={`alert__backdrop${exiting ? ' alert__backdrop--exiting' : ''}`}
116→      onClick={handleBackdropClick}
117→      role="presentation"
118→    >
119→      <div
120→        className={`alert__dialog${exiting ? ' alert__dialog--exiting' : ''}`}
121→        ref={dialogRef}
122→        role="alertdialog"
123→        aria-modal="true"
124→        aria-labelledby={titleId}
125→        aria-describedby={message ? messageId : undefined}
126→      >
127→        {icon && <div className="alert__icon">{icon}</div>}
128→        <h2 className="alert__title" id={titleId}>
129→          {title}
130→        </h2>
131→        {message && (
132→          <p className="alert__message" id={messageId}>
133→            {message}
134→          </p>
135→        )}
136→        <div className="alert__actions">
137→          {dismissAction && (
138→            <button
139→              type="button"
140→              className="alert__button alert__button--cancel"
141→              onClick={handleDismissClick}
142→            >
143→              {dismissAction.label}
144→            </button>
145→          )}
146→          <button
147→            type="button"
148→            className={primaryClassName}
149→            onClick={handlePrimaryClick}
150→            ref={primaryRef}
151→          >
152→            {primaryAction.label}
153→          </button>
154→        </div>
155→      </div>
156→    </div>
157→  );
158→}
